			const idle = data.tasks.filter((t) => t.status === "idle").length;
			const totalCost = data.tasks.reduce((sum, t) => sum + t.cost, 0);

			const lines: string[] = [];
			lines.push(
				`${data.listTitle} [${done}/${total} done, ${active} active, ${idle} idle] $${totalCost.toFixed(2)}`
			);

			for (const t of data.tasks) {
				const icon = STATUS_ICON[t.status];
				const branchInfo = t.branch ? ` (${t.branch})` : "";
				const prInfo = t.pr ? ` PR: ${t.pr}` : "";
				lines.push(`  ${icon} #${t.id} [${t.status}] ${t.text}${branchInfo}${prInfo}`);
			}

			return lines.join("\n");
		},
	};

	return store;
}

/**
 * TaskStore — Persistent CRUD for `.pi/tasks/tasks.json`
 *
 * Every mutating operation writes to disk immediately via fs.writeFileSync.
 * Single active task invariant: toggling a task to inprogress demotes any
 * other inprogress task to idle.
 */

import * as fs from "fs";
import * as path from "path";

// ── Types ──────────────────────────────────────────────────────────────

export type TaskStatus = "idle" | "inprogress" | "done";

export interface Task {
	id: number;
	text: string;
	status: TaskStatus;
	branch: string | null;
	pr: string | null;
	created: string; // ISO 8601
	completed: string | null;
	cost: number; // accumulated cost in dollars
}

export interface TaskStoreData {
	nextId: number;
	listTitle: string;
	tasks: Task[];
}

export interface TaskStore {
	// Read
	getAll(): Task[];
	getById(id: number): Task | undefined;
	getActive(): Task | undefined; // the single in-progress task
	getTitle(): string;

	// Write
	add(text: string): Task;
	addBatch(texts: string[]): Task[];
	toggle(id: number): Task; // idle->inprogress->done cycle, demotes other active tasks
	remove(id: number): void;
	update(id: number, text: string): void;
	clear(): void;
	newList(title: string): void;

	// Git integration
	setBranch(id: number, branch: string): void;
	setPr(id: number, pr: string): void;
	addCost(id: number, amount: number): void;

	// State
	getData(): TaskStoreData;
	hasActiveTasks(): boolean; // any non-done tasks exist
	summary(): string; // human-readable summary for compaction injection
}

// ── Status cycle ───────────────────────────────────────────────────────

const NEXT_STATUS: Record<TaskStatus, TaskStatus> = {
	idle: "inprogress",
	inprogress: "done",
	done: "idle",
};

const STATUS_ICON: Record<TaskStatus, string> = {
	idle: "○",
	inprogress: "●",
	done: "✓",
};

// ── Helpers ────────────────────────────────────────────────────────────

function freshData(): TaskStoreData {
	return { nextId: 1, listTitle: "pi-shell session", tasks: [] };
}

function isValidData(obj: unknown): obj is TaskStoreData {
	if (typeof obj !== "object" || obj === null) return false;
	const d = obj as Record<string, unknown>;
	return (
		typeof d.nextId === "number" &&
		typeof d.listTitle === "string" &&
		Array.isArray(d.tasks)
	);
}

// ── Factory ────────────────────────────────────────────────────────────

export function createTaskStore(cwd?: string): TaskStore {
	const root = cwd || process.cwd();
	const dir = path.join(root, ".pi", "tasks");
	const filePath = path.join(dir, "tasks.json");

	// Load or create fresh state
	let data: TaskStoreData = load();

	function load(): TaskStoreData {
		try {
			if (fs.existsSync(filePath)) {
				const raw = fs.readFileSync(filePath, "utf-8");
				const parsed = JSON.parse(raw);
				if (isValidData(parsed)) {
					// Coerce null costs to 0 (can happen with older data)
					for (const t of parsed.tasks) {
						if (t.cost == null) t.cost = 0;
					}
					return parsed;
				}
			}
		} catch {
			// Corrupt or missing — fall through to fresh state
		}
		return freshData();
	}

	function save(): void {
		fs.mkdirSync(dir, { recursive: true });
		fs.writeFileSync(filePath, JSON.stringify(data, null, 2) + "\n", "utf-8");
	}

	function findTask(id: number): Task {
		const task = data.tasks.find((t) => t.id === id);
		if (!task) throw new Error(`Task #${id} not found`);
		return task;
	}

	const store: TaskStore = {
		// ── Read ───────────────────────────────────────────────────────

		getAll(): Task[] {
			return [...data.tasks];
		},

		getById(id: number): Task | undefined {
			return data.tasks.find((t) => t.id === id);
		},

		getActive(): Task | undefined {
			return data.tasks.find((t) => t.status === "inprogress");
		},

		getTitle(): string {
			return data.listTitle;
		},

		// ── Write ──────────────────────────────────────────────────────

		add(text: string): Task {
			const task: Task = {
				id: data.nextId++,
				text,
				status: "idle",
				branch: null,
				pr: null,
				created: new Date().toISOString(),
				completed: null,
				cost: 0,
			};
			data.tasks.push(task);
			save();
			return task;
		},

		addBatch(texts: string[]): Task[] {
			const added: Task[] = [];
			for (const text of texts) {
				const task: Task = {
					id: data.nextId++,
					text,
					status: "idle",
					branch: null,
					pr: null,
					created: new Date().toISOString(),
					completed: null,
					cost: 0,
				};
				data.tasks.push(task);
				added.push(task);
			}
			save();
			return added;
		},

		toggle(id: number): Task {
			const task = findTask(id);
			const prev = task.status;
			task.status = NEXT_STATUS[prev];

			// When toggling TO inprogress, demote any other inprogress task
			if (task.status === "inprogress") {
				for (const t of data.tasks) {
					if (t.id !== task.id && t.status === "inprogress") {
						t.status = "idle";
					}
				}
			}

			// When toggling TO done, set completed timestamp
			if (task.status === "done") {
				task.completed = new Date().toISOString();
			}

			// When toggling FROM done back to idle, clear completed
			if (prev === "done" && task.status === "idle") {
				task.completed = null;
			}

			save();
			return task;
		},

		remove(id: number): void {
			const idx = data.tasks.findIndex((t) => t.id === id);
			if (idx === -1) throw new Error(`Task #${id} not found`);
			data.tasks.splice(idx, 1);
			save();
		},

		update(id: number, text: string): void {
			const task = findTask(id);
			task.text = text;
			save();
		},

		clear(): void {
			data.tasks = [];
			data.nextId = 1;
			save();
		},

		newList(title: string): void {
			data = { nextId: 1, listTitle: title, tasks: [] };
			save();
		},

		// ── Git integration ────────────────────────────────────────────

		setBranch(id: number, branch: string): void {
			const task = findTask(id);
			task.branch = branch;
			save();
		},

		setPr(id: number, pr: string): void {
			const task = findTask(id);
			task.pr = pr;
			save();
		},

		addCost(id: number, amount: number): void {
			const task = findTask(id);
			task.cost = Math.round((task.cost + amount) * 1e6) / 1e6;
			save();
		},

		// ── State ──────────────────────────────────────────────────────

		getData(): TaskStoreData {
			return { ...data, tasks: [...data.tasks] };
		},

		hasActiveTasks(): boolean {
			return data.tasks.some((t) => t.status !== "done");
		},

		summary(): string {
			const total = data.tasks.length;
			if (total === 0) return `${data.listTitle}: no tasks`;

			const done = data.tasks.filter((t) => t.status === "done").length;
			const active = data.tasks.filter((t) => t.status === "inprogress").length;
			const idle = data.tasks.filter((t) => t.status === "idle").length;
			const totalCost = data.tasks.reduce((sum, t) => sum + t.cost, 0);

			const lines: string[] = [];
			lines.push(
				`${data.listTitle} [${done}/${total} done, ${active} active, ${idle} idle] $${totalCost.toFixed(2)}`
			);

			for (const t of data.tasks) {
				const icon = STATUS_ICON[t.status];
				const branchInfo = t.branch ? ` (${t.branch})` : "";
				const prInfo = t.pr ? ` PR: ${t.pr}` : "";
				lines.push(`  ${icon} #${t.id} [${t.status}] ${t.text}${branchInfo}${prInfo}`);
			}

			return lines.join("\n");
		},
	};

	return store;
}

/**
 * spawnSubagent — Shared subprocess spawner for pi-shell
 *
 * Used by both `dispatch_agent` and `answer` tools.
 * Spawns a `pi` child process in --mode json, parses JSONL events from
 * stdout, extracts cost data, streams progress, and handles timeout /
 * cancellation.
 */

import { spawn, execSync } from "child_process";
import { readFileSync, mkdirSync, appendFileSync, existsSync } from "fs";
import { join } from "path";
import { parse as yamlParse } from "yaml";

// ── Types ──────────────────────────────────────────────────────────────

export interface SpawnOptions {
	agent: string;           // agent name (maps to .pi/agents/<name>.md)
	task: string;            // task prompt for the subagent
	model?: string;          // model override (from config agent_models)
	branch?: string;         // git branch to work on (dispatch_agent passes this)
	cwd: string;             // working directory
	timeout: number;         // max runtime in seconds
	maxResultTokens: number; // truncation limit for result
	sessionDir: string;      // directory for session files (.pi/tasks/sessions/)
	taskId: number;          // task ID for session file naming
	signal?: AbortSignal;    // for cancellation
	onUpdate?: (data: { type: string; content: string }) => void;  // streaming updates
	onCostUpdate?: (cost: number) => void;  // cost extracted from message_end events
}

export interface SpawnResult {
	output: string;   // truncated subagent output
	exitCode: number;
	cost: number;     // total cost from this subagent run
	elapsed: number;  // milliseconds
	conflict: boolean;
	actualBranch?: string;
}

// ── Agent Definition Parser ────────────────────────────────────────────

interface AgentDef {
	name: string;
	description: string;
	tools: string;
	systemPrompt: string;
}

/**
 * Read and parse an agent definition from .pi/agents/<name>.md.
 * Expects YAML frontmatter delimited by --- lines, followed by body text.
 */
function loadAgentDef(agentName: string, cwd: string): AgentDef | null {
	const filePath = join(cwd, ".pi", "agents", `${agentName}.md`);
	try {
		const raw = readFileSync(filePath, "utf-8");
		const match = raw.match(/^---\n([\s\S]*?)\n---\n([\s\S]*)$/);
		if (!match) return null;

		const frontmatter = yamlParse(match[1]) as Record<string, string>;
		if (!frontmatter?.name) return null;

		return {
			name: frontmatter.name,
			description: frontmatter.description || "",
			tools: frontmatter.tools || "read,bash,grep",
			systemPrompt: match[2].trim(),
		};
	} catch {
		return null;
	}
}

// ── Git Branch Helpers ─────────────────────────────────────────────────

function checkoutBranch(branch: string, cwd: string): string {
	try {
		execSync(`git checkout ${branch}`, { cwd, stdio: "ignore" });
		return branch;
	} catch {
		try {
			execSync(`git checkout -b ${branch}`, { cwd, stdio: "ignore" });
			return branch;
		} catch {
			const fallback = `${branch}_${Date.now()}`;
			execSync(`git checkout -b ${fallback}`, { cwd, stdio: "ignore" });
			return fallback;
		}
	}
}

function checkoutPreviousBranch(cwd: string): void {
	try {
		execSync("git checkout -", { cwd, stdio: "ignore" });
	} catch {
		// Best-effort — if it fails, stay on current branch
	}
}

// ── Main Spawn Function ───────────────────────────────────────────────

export async function spawnSubagent(options: SpawnOptions): Promise<SpawnResult> {
	const {
		agent,
		task,
		model,
		branch,
		cwd,
		timeout,
		maxResultTokens,
		sessionDir,
		taskId,
		signal,
		onUpdate,
		onCostUpdate,
	} = options;

	// Load agent definition
	const agentDef = loadAgentDef(agent, cwd);
	if (!agentDef) {
		return {
			output: `Agent "${agent}" not found. No .pi/agents/${agent}.md definition.`,
			exitCode: 1,
			cost: 0,
			elapsed: 0,
			conflict: false,
		};
	}

	// Ensure session directory exists
	mkdirSync(sessionDir, { recursive: true });

	// Session file for JSONL logging
	const sessionFile = join(sessionDir, `${agent}-${taskId}.jsonl`);

	// Switch to target branch if specified
	let actualBranch: string | undefined;
	if (branch) {
		try {
			actualBranch = checkoutBranch(branch, cwd);
		} catch (err: any) {
			return {
				output: `Failed to checkout branch "${branch}": ${err?.message || err}`,
				exitCode: 1,
				cost: 0,
				elapsed: 0,
				conflict: false,
			};
		}
	}

	// Build pi args
	const args: string[] = [
		"--mode", "json",
		"--no-session",
		"--system-prompt", agentDef.systemPrompt,
		"--tools", agentDef.tools,
		"--thinking", "off",
	];

	if (model) {
		args.push("--model", model);
	}

	// The task prompt is the initial user message (positional arg)
	args.push(task);

	const startTime = Date.now();
	let totalCost = 0;
	let conflictDetected = false;
	const textChunks: string[] = [];

	return new Promise<SpawnResult>((resolve) => {
		const proc = spawn("pi", args, {
			cwd,
			stdio: ["ignore", "pipe", "pipe"],
			env: { ...process.env },
		});

		let buffer = "";
		let killed = false;

		// Timeout handling
		const timeoutTimer = setTimeout(() => {
			if (!killed) {
				killed = true;
				proc.kill("SIGTERM");
				// Give it a moment, then SIGKILL
				setTimeout(() => {
					try { proc.kill("SIGKILL"); } catch { /* already dead */ }
				}, 2000);
			}
		}, timeout * 1000);

		// Abort signal handling
		const onAbort = () => {
			if (!killed) {
				killed = true;
				proc.kill("SIGTERM");
			}
		};
		if (signal) {
			if (signal.aborted) {
				killed = true;
				proc.kill("SIGTERM");
			} else {
				signal.addEventListener("abort", onAbort, { once: true });
			}
		}

		function processLine(line: string): void {
			if (!line.trim()) return;

			// Append raw JSONL to session file
			try {
				appendFileSync(sessionFile, line + "\n");
			} catch { /* best-effort logging */ }

			try {
				const event = JSON.parse(line);

				if (event.type === "message_update") {
					const delta = event.assistantMessageEvent;
					if (delta?.type === "text_delta") {
						const text = delta.delta || "";
						textChunks.push(text);
						if (!conflictDetected && /conflict|merge conflict/i.test(text)) {
							conflictDetected = true;
						}
						if (onUpdate) {
							onUpdate({ type: "text_delta", content: text });
						}
					}
				} else if (event.type === "message_end") {
					const msg = event.message;
					// Surface error messages so they're not swallowed
					if (msg?.stopReason === "error" && msg?.errorMessage) {
						textChunks.push(`[Error] ${msg.errorMessage}`);
					}
					// Extract cost from message_end events
					if (msg?.usage?.cost != null) {
						totalCost += msg.usage.cost;
						if (onCostUpdate) {
							onCostUpdate(totalCost);
						}
					} else if (msg?.usage) {
						// Some providers report input/output tokens but not cost directly
						// Try to extract from the event's top-level cost field
						if (event.cost != null) {
							totalCost += event.cost;
							if (onCostUpdate) {
								onCostUpdate(totalCost);
							}
						}
					}
				} else if (event.type === "tool_execution_start") {
					if (onUpdate) {
						const toolName = event.toolName || event.name || "tool";
						onUpdate({ type: "tool_start", content: toolName });
					}
				} else if (event.type === "agent_end") {
					// Final event — may contain cost summary
					if (event.cost != null && event.cost > totalCost) {
						totalCost = event.cost;
						if (onCostUpdate) {
							onCostUpdate(totalCost);
						}
					}
				}
			} catch {
				// Non-JSON line or parse error — ignore
			}
		}

		proc.stdout!.setEncoding("utf-8");
		proc.stdout!.on("data", (chunk: string) => {
			buffer += chunk;
			const lines = buffer.split("\n");
			buffer = lines.pop() || "";
			for (const line of lines) {
				processLine(line);
			}
		});

		// Capture stderr but don't process it (just drain)
		proc.stderr!.setEncoding("utf-8");
		proc.stderr!.on("data", () => {});

		proc.on("close", (code) => {
			clearTimeout(timeoutTimer);
			if (signal) {
				signal.removeEventListener("abort", onAbort);
			}

			// Process remaining buffer
			if (buffer.trim()) {
				processLine(buffer);
			}

			// Switch back to previous branch if we checked one out
			if (branch) {
				checkoutPreviousBranch(cwd);
			}

			const elapsed = Date.now() - startTime;
			const fullOutput = textChunks.join("");

			// Truncate to maxResultTokens characters
			const output = fullOutput.length > maxResultTokens
				? fullOutput.slice(0, maxResultTokens) + "\n\n... [truncated]"
				: fullOutput;

			resolve({
				output,
				exitCode: killed && code !== 0 ? (code ?? 124) : (code ?? 1),
				cost: totalCost,
				elapsed,
				conflict: conflictDetected,
				actualBranch,
			});
		});

		proc.on("error", (err) => {
			clearTimeout(timeoutTimer);
			if (signal) {
				signal.removeEventListener("abort", onAbort);
			}

			// Switch back if needed
			if (branch) {
				checkoutPreviousBranch(cwd);
			}

			resolve({
				output: `Error spawning pi subprocess: ${err.message}`,
				exitCode: 1,
				cost: totalCost,
				elapsed: Date.now() - startTime,
				conflict: conflictDetected,
				actualBranch,
			});
		});
	});
}

